// Helper functions
export function getDemoBySlug(slug: string) {
  return demos.find(d => d.slug === slug) || null;
}

export function getDemosByCategory(catSlug: string) {
  return demos.filter(d => d.cat === catSlug);
}

export function getAllDemoCategories() {
  return demoCategories;
}

// Count total demos
export function totalDemoCount() {
  return demos.length;
}
